import React from 'react'
import Header from './Header';
import Footer from './Footer';
import MainlLayout from './MainlLayout';
import SideBar from './SideBar';

const DefaultLayout = () => {
  return (
    <div>
      <Header />
      <SideBar />
      <div className="wrapper d-flex flex-column min-vh-100 wseInfratechBodyBG pt-4">
        <div className="body flex-grow-1 px-3"> <MainlLayout /></div>
        <Footer />
      </div>
    </div>
  )
}

export default DefaultLayout;
